import React, { forwardRef, useImperativeHandle } from 'react';
import { useTranslation } from 'react-i18next';
import { AlertCircle, CheckCircle, Info } from 'lucide-react';
import '../../styles/WalletForm.css';

/**
 * WalletForm Component
 * Reusable form component for AddFunds and Withdraw pages
 * 
 * @param {Object} props
 * @param {Object} props.formData - Form field values
 * @param {Object} props.errors - Validation errors
 * @param {function} props.onChange - Field change handler
 * @param {function} props.onSubmit - Form submit handler
 * @param {Array} props.fields - Field configuration array
 * @param {Array} props.quickValues - Quick select values (for amounts)
 * @param {string} props.currency - Currency code
 * @param {boolean} props.loading - Form loading state
 * @param {string} props.submitLabel - Submit button text
 * @param {React.ReactNode} props.footer - Optional footer content
 * @param {Object} props.summary - Optional summary data to display
 */
const WalletForm = forwardRef(function WalletForm(
  {
    formData = {},
    errors = {},
    onChange,
    onSubmit,
    fields = [],
    quickValues = [],
    currency = 'USD',
    loading = false,
    submitLabel = 'Submit',
    footer,
    summary
  },
  ref
) {
  const { t } = useTranslation();

  // Expose methods to parent via ref
  useImperativeHandle(ref, () => ({
    reset: () => {
      // Trigger custom reset if needed
      const event = new CustomEvent('formReset');
      window.dispatchEvent(event);
    },
    validate: () => {
      // Trigger validation
      return Object.keys(errors).length === 0;
    }
  }));

  const handleFieldChange = (field, value) => {
    onChange?.(field, value);
  };

  const handleQuickSelect = (field, value) => {
    handleFieldChange(field, value);
  };

  const renderField = (field) => {
    const {
      name,
      type = 'text',
      label,
      placeholder,
      required = false,
      prefix,
      suffix,
      options = [],
      quickSelect = false,
      info,
      ...rest
    } = field;

    const value = formData[name] || '';
    const error = errors[name];

    // Quick select buttons (for amounts)
    if (quickSelect && quickValues.length > 0) {
      return (
        <div key={name} className="form-group">
          {label && (
            <label className="form-label" htmlFor={name}>
              {label}
              {required && <span className="required">*</span>}
            </label>
          )}
          
          <div className="quick-select-group">
            {quickValues.map((val) => (
              <button
                key={val}
                type="button"
                className={`quick-select-btn ${value == val ? 'active' : ''}`}
                onClick={() => handleQuickSelect(name, val)}
                disabled={loading}
              >
                {prefix}{val}{suffix}
              </button>
            ))}
          </div>
          
          <div className="input-wrapper">
            {prefix && <span className="input-prefix">{prefix}</span>}
            <input
              id={name}
              name={name}
              type={type}
              value={value}
              placeholder={placeholder}
              required={required}
              disabled={loading}
              onChange={(e) => handleFieldChange(name, e.target.value)}
              className={`form-input ${error ? 'error' : ''}`}
              {...rest}
            />
            {suffix && <span className="input-suffix">{suffix}</span>}
          </div>
          {error && (
            <p className="form-error" role="alert">
              <AlertCircle size={14} />
              {error}
            </p>
          )}
          {info && (
            <p className="form-info">
              <Info size={14} />
              {info}
            </p>
          )}
        </div>
      );
    }

    // Select dropdown
    if (type === 'select') {
      return (
        <div key={name} className="form-group">
          {label && (
            <label className="form-label" htmlFor={name}>
              {label}
              {required && <span className="required">*</span>}
            </label>
          )}
          <select
            id={name}
            name={name}
            value={value}
            required={required}
            disabled={loading}
            onChange={(e) => handleFieldChange(name, e.target.value)}
            className={`form-select ${error ? 'error' : ''}`}
            {...rest}
          >
            <option value="">{placeholder || t('common.select')}</option>
            {options.map((opt) => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
          {error && (
            <p className="form-error" role="alert">
              <AlertCircle size={14} />
              {error}
            </p>
          )}
        </div>
      );
    }

    // Textarea
    if (type === 'textarea') {
      return (
        <div key={name} className="form-group">
          {label && (
            <label className="form-label" htmlFor={name}>
              {label}
              {required && <span className="required">*</span>}
            </label>
          )}
          <textarea
            id={name}
            name={name}
            value={value}
            placeholder={placeholder}
            required={required}
            disabled={loading}
            onChange={(e) => handleFieldChange(name, e.target.value)}
            className={`form-textarea ${error ? 'error' : ''}`}
            rows={rest.rows || 4}
            {...rest}
          />
          {error && (
            <p className="form-error" role="alert">
              <AlertCircle size={14} />
              {error}
            </p>
          )}
        </div>
      );
    }

    // Checkbox
    if (type === 'checkbox') {
      return (
        <div key={name} className="form-group checkbox-group">
          <label className="checkbox-label">
            <input
              type="checkbox"
              name={name}
              checked={!!value}
              disabled={loading}
              onChange={(e) => handleFieldChange(name, e.target.checked)}
              className="form-checkbox"
              {...rest}
            />
            <span className="checkbox-text">{label}</span>
          </label>
          {error && (
            <p className="form-error" role="alert">
              <AlertCircle size={14} />
              {error}
            </p>
          )}
        </div>
      );
    }

    // Default input
    return (
      <div key={name} className="form-group">
        {label && (
          <label className="form-label" htmlFor={name}>
            {label}
            {required && <span className="required">*</span>}
          </label>
        )}
        <div className="input-wrapper">
          {prefix && <span className="input-prefix">{prefix}</span>}
          <input
            id={name}
            name={name}
            type={type}
            value={value}
            placeholder={placeholder}
            required={required}
            disabled={loading}
            onChange={(e) => handleFieldChange(name, e.target.value)}
            className={`form-input ${error ? 'error' : ''}`}
            {...rest}
          />
          {suffix && <span className="input-suffix">{suffix}</span>}
        </div>
        {error && (
          <p className="form-error" role="alert">
            <AlertCircle size={14} />
            {error}
          </p>
        )}
        {info && (
          <p className="form-info">
            <Info size={14} />
            {info}
          </p>
        )}
      </div>
    );
  };

  return (
    <form onSubmit={onSubmit} className="wallet-form" noValidate>
      {/* Form Summary */}
      {summary && (
        <div className="form-summary">
          {Object.entries(summary).map(([key, val]) => (
            <div key={key} className="summary-row">
              <span className="summary-label">{key}</span>
              <span className="summary-value">{val}</span>
            </div>
          ))}
        </div>
      )}

      {/* Form Fields */}
      <div className="form-fields">
        {fields.map(renderField)}
      </div>

      {/* Form Footer */}
      {footer && <div className="form-footer">{footer}</div>}

      {/* Submit Button */}
      <div className="form-actions">
        <button
          type="submit"
          className="btn btn-primary btn-submit"
          disabled={loading}
        >
          {loading ? (
            <>
              <span className="btn-spinner" />
              {t('common.processing')}
            </>
          ) : (
            <>
              {submitLabel}
              <CheckCircle size={16} />
            </>
          )}
        </button>
      </div>
    </form>
  );
});

export default WalletForm;
